// Hero background photo — replace this with a real photo of the Defne Auto
// showroom/lot once available. In the real deployment this should live at
// /public/hero.jpg and be referenced as "/hero.jpg" instead of a URL.
const HERO_IMAGE_SRC = "https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?q=80&w=1800&auto=format&fit=crop";

const TL = (n) => n.toLocaleString("tr-TR") + " ₺";
const KM = (n) => n.toLocaleString("tr-TR") + " km";

// Logo image — in the real deployment this should live at /public/logo.png
// and be referenced as <img src="/logo.png" /> instead of a data URI.
const LOGO_SRC = "data:image/png;base64,";

// ---------------------------------------------------------------------------
function Logo({ size = 1, light = false }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8 * size }}>
      <img
        src={LOGO_SRC}
        alt="Defne Auto"
        style={{ height: 64 * size, width: "auto", objectFit: "contain", flexShrink: 0 }}
      />
      <div style={{
        fontSize: 10 * size, color: light ? "#C9BCB0" : "#8A95A3",
        letterSpacing: 1.6, fontWeight: 500, marginTop: 2 * size, marginLeft: -2,
      }}>
        OTO GALERİ
      </div>
    </div>
  );
}

function StatusBadge({ status }) {
  const map = {
    active: { bg: "#E6F6EC", fg: "#1A7A3E", label: "Yayında", icon: CheckCircle2 },
    pending: { bg: "#FFF3DD", fg: "#A86A00", label: "Senkronize Ediliyor", icon: Clock },
    hidden: { bg: "#F1F2F4", fg: "#6B7280", label: "Pasif", icon: EyeOff },
  };
  const s = map[status] || map.active;
  const Icon = s.icon;
  return (
    <span style={{
      display: "inline-flex", alignItems: "center", gap: 5,
      background: s.bg, color: s.fg, fontSize: 12, fontWeight: 600,
      padding: "4px 10px", borderRadius: 20, lineHeight: 1,
    }}>
      <Icon size={12.5} strokeWidth={2.5} />
      {s.label}
    </span>
  );
}

function CarCard({ car, onOpen }) {
  return (
    <div
      onClick={() => onOpen(car)}
      style={{
        background: "#fff", borderRadius: 14, overflow: "hidden", cursor: "pointer",
        border: "1px solid #EAECEF", transition: "transform .18s ease, box-shadow .18s ease",
        display: "flex", flexDirection: "column",
      }}
      onMouseEnter={(e) => { e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.boxShadow = "0 16px 32px rgba(39,36,31,0.12)"; }}
      onMouseLeave={(e) => { e.currentTarget.style.transform = "translateY(0)"; e.currentTarget.style.boxShadow = "none"; }}
    >
      <div style={{ position: "relative", aspectRatio: "16/10.5", overflow: "hidden", background: "#27241F" }}>
        <img src={car.img} alt={car.title} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
        <div style={{ position: "absolute", top: 10, left: 10 }}>
          <StatusBadge status={car.status} />
        </div>
        <div style={{
          position: "absolute", bottom: 0, left: 0, right: 0, height: 56,
          background: "linear-gradient(to top, rgba(39,36,31,0.55), transparent)",
        }} />
      </div>
      <div style={{ padding: "14px 16px 16px", display: "flex", flexDirection: "column", gap: 10, flex: 1 }}>
        <div style={{ fontFamily: "Oswald,sans-serif", fontWeight: 600, fontSize: 16, color: "#2A2622", lineHeight: 1.3 }}>
          {car.title}
        </div>
        <div style={{ display: "flex", gap: 14, fontSize: 12.5, color: "#6B7280", flexWrap: "wrap" }}>
          <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Calendar size={13} />{car.year}</span>
          <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Gauge size={13} />{KM(car.km)}</span>
          <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Fuel size={13} />{car.fuel}</span>
          <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Settings2 size={13} />{car.gear}</span>
        </div>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginTop: "auto", paddingTop: 6 }}>
          <div style={{ fontFamily: "Oswald,sans-serif", fontWeight: 600, fontSize: 19, color: "#27241F" }}>
            {TL(car.price)}
          </div>
          <div style={{
            display: "flex", alignItems: "center", gap: 3, color: "#D1A564", fontSize: 13, fontWeight: 600,
          }}>
            Detay <ChevronRight size={15} />
          </div>
        </div>
      </div>
    </div>
  );
}

function Filters({ filters, setFilters, brands, resultCount }) {
  const inputStyle = {
    width: "100%", padding: "10px 12px", borderRadius: 9, border: "1px solid #E2E5EA",
    fontSize: 14, color: "#2A2622", background: "#fff", outline: "none", fontFamily: "Inter,sans-serif",
  };
  const labelStyle = { fontSize: 11.5, fontWeight: 600, color: "#8B93A1", marginBottom: 6, display: "block", letterSpacing: 0.3, textTransform: "uppercase" };
  return (
    <div style={{
      background: "#fff", borderRadius: 16, padding: 20, boxShadow: "0 20px 45px rgba(39,36,31,0.18)",
      display: "grid", gridTemplateColumns: "1.3fr 1fr 1fr 1fr auto", gap: 14, alignItems: "end",
    }}
    className="da-filter-grid"
    >
      <div>
        <label style={labelStyle}>Marka</label>
        <select style={inputStyle} value={filters.brand} onChange={(e) => setFilters((f) => ({ ...f, brand: e.target.value }))}>
          <option value="">Tüm markalar</option>
          {brands.map((b) => <option key={b} value={b}>{b}</option>)}
        </select>
      </div>
      <div>
        <label style={labelStyle}>Yakıt</label>
        <select style={inputStyle} value={filters.fuel} onChange={(e) => setFilters((f) => ({ ...f, fuel: e.target.value }))}>
          <option value="">Tümü</option>
          <option>Benzin</option>
          <option>Dizel</option>
          <option>Hibrit</option>
          <option>Elektrik</option>
        </select>
      </div>
      <div>
        <label style={labelStyle}>Vites</label>
        <select style={inputStyle} value={filters.gear} onChange={(e) => setFilters((f) => ({ ...f, gear: e.target.value }))}>
          <option value="">Tümü</option>
          <option>Manuel</option>
          <option>Otomatik</option>
        </select>
      </div>
      <div>
        <label style={labelStyle}>Maks. Fiyat</label>
        <select style={inputStyle} value={filters.maxPrice} onChange={(e) => setFilters((f) => ({ ...f, maxPrice: e.target.value }))}>
          <option value="">Sınırsız</option>
          <option value="600000">600.000 ₺</option>
          <option value="900000">900.000 ₺</option>
          <option value="1200000">1.200.000 ₺</option>
          <option value="1500000">1.500.000 ₺</option>
        </select>
      </div>
      <button style={{
        display: "flex", alignItems: "center", justifyContent: "center", gap: 7,
        background: "#D1A564", color: "#27241F", border: "none", borderRadius: 9,
        padding: "11px 18px", fontWeight: 700, fontSize: 14, cursor: "pointer", whiteSpace: "nowrap",
      }}>
        <Search size={16} strokeWidth={2.5} /> {resultCount} araç
      </button>
    </div>
  );
}

function PublicSite({ cars, goAdmin }) {
  const [filters, setFilters] = useState({ brand: "", fuel: "", gear: "", maxPrice: "" });
  const [selected, setSelected] = useState(null);

  const visibleCars = cars.filter((c) => c.status !== "hidden");
  const brands = useMemo(() => [...new Set(visibleCars.map((c) => c.brand))].sort(), [visibleCars]);

  const filtered = visibleCars.filter((c) =>
    (!filters.brand || c.brand === filters.brand) &&
    (!filters.fuel || c.fuel === filters.fuel) &&
    (!filters.gear || c.gear === filters.gear) &&
    (!filters.maxPrice || c.price <= Number(filters.maxPrice))
  );

  return (
    <div style={{ fontFamily: "Inter,sans-serif", background: "#F5F6F8", minHeight: "100%" }}>
      {/* NAV */}
      <header style={{ background: "#27241F", padding: "10px 28px" }}>
        <div style={{ maxWidth: 1180, margin: "0 auto", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <Logo light />
          <nav style={{ display: "flex", alignItems: "center", gap: 28 }}>
            <span style={{ color: "#E4DCD3", fontSize: 14.5, fontWeight: 500, cursor: "pointer" }}>Araçlar</span>
            <span style={{ color: "#E4DCD3", fontSize: 14.5, fontWeight: 500, cursor: "pointer" }}>Hakkımızda</span>
            <span style={{ color: "#E4DCD3", fontSize: 14.5, fontWeight: 500, cursor: "pointer" }}>İletişim</span>
            <a href="tel:+905001234567" style={{
              display: "flex", alignItems: "center", gap: 7, background: "rgba(209,165,100,0.15)",
              color: "#D1A564", padding: "8px 14px", borderRadius: 8, fontSize: 13.5, fontWeight: 600,
              textDecoration: "none",
            }}>
              <Phone size={14} /> 0500 123 45 67
            </a>
            <button onClick={goAdmin} style={{
              background: "transparent", border: "1px solid #544A40", color: "#C9BCB0",
              borderRadius: 8, padding: "7px 12px", fontSize: 12.5, cursor: "pointer", fontWeight: 500,
            }}>
              Yönetim Paneli
            </button>
          </nav>
        </div>
      </header>

      {/* HERO */}
      <div style={{
        position: "relative", overflow: "hidden", padding: "64px 28px 90px",
      }}>
        <img
          src={HERO_IMAGE_SRC}
          alt=""
          aria-hidden="true"
          style={{
            position: "absolute", inset: 0, width: "100%", height: "100%",
            objectFit: "cover", objectPosition: "center 35%",
          }}
        />
        <div style={{
          position: "absolute", inset: 0,
          background: "linear-gradient(160deg, rgba(39,36,31,0.94) 0%, rgba(39,36,31,0.88) 45%, rgba(53,47,41,0.80) 100%)",
        }} />
        <div style={{
          position: "absolute", right: -80, top: -60, width: 420, height: 420, borderRadius: "50%",
          background: "radial-gradient(circle,rgba(209,165,100,0.18),transparent 70%)",
        }} />
        <div style={{ maxWidth: 1180, margin: "0 auto", position: "relative", textAlign: "center", display: "flex", flexDirection: "column", alignItems: "center" }}>
          <img
            src={LOGO_SRC}
            alt="Defne Auto"
            style={{ height: 150, width: "auto", objectFit: "contain", marginBottom: 22, filter: "drop-shadow(0 8px 24px rgba(0,0,0,0.45))" }}
          />
          <div style={{
            display: "inline-flex", alignItems: "center", gap: 6, background: "rgba(209,165,100,0.18)",
            color: "#D1A564", padding: "6px 13px", borderRadius: 20, fontSize: 12.5, fontWeight: 600, marginBottom: 18,
            border: "1px solid rgba(209,165,100,0.3)",
          }}>
            <Sparkles size={13} /> Isparta'nın güncel ikinci el galerisi
          </div>
          <h1 style={{
            fontFamily: "Oswald,sans-serif", color: "#fff", fontSize: 38, fontWeight: 600,
            maxWidth: 640, lineHeight: 1.15, margin: "0 0 12px", textShadow: "0 2px 12px rgba(0,0,0,0.4)",
          }}>
            Aradığın araç, <span style={{ color: "#D1A564" }}>Defne Auto'da.</span>
          </h1>
          <p style={{ color: "#E4DCD3", fontSize: 16, maxWidth: 480, margin: "0 0 36px", textShadow: "0 1px 8px rgba(0,0,0,0.35)" }}>
            Galerimizdeki tüm araçlar sahibinden ilanlarımızla canlı senkronize — gördüğün her araç güncel ve müsait.
          </p>
        </div>
      </div>

      {/* FILTER BAR (overlapping hero) */}
      <div style={{ maxWidth: 1180, margin: "-56px auto 0", padding: "0 28px", position: "relative", zIndex: 5 }}>
        <Filters filters={filters} setFilters={setFilters} brands={brands} resultCount={filtered.length} />
      </div>

      {/* GRID */}
      <div style={{ maxWidth: 1180, margin: "0 auto", padding: "48px 28px 80px" }}>
        <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between", marginBottom: 22 }}>
          <h2 style={{ fontFamily: "Oswald,sans-serif", fontSize: 22, color: "#2A2622", fontWeight: 600, margin: 0 }}>
            Güncel İlanlar
          </h2>
          <span style={{ fontSize: 13, color: "#8B93A1", display: "flex", alignItems: "center", gap: 6 }}>
            <RefreshCw size={13} /> Sahibinden ile otomatik senkronize
          </span>
        </div>

        {filtered.length === 0 ? (
          <div style={{
            background: "#fff", borderRadius: 14, padding: "60px 20px", textAlign: "center", color: "#8B93A1",
            border: "1px dashed #E2E5EA",
          }}>
            Bu filtrelere uyan araç bulunamadı. Filtreleri değiştirip yeniden dene.
          </div>
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 20 }} className="da-card-grid">
            {filtered.map((c) => <CarCard key={c.id} car={c} onOpen={setSelected} />)}
          </div>
        )}
      </div>

      <footer style={{ background: "#27241F", padding: "28px", textAlign: "center", color: "#9A8E83", fontSize: 13 }}>
        © 2026 Defne Auto Oto Galeri — Isparta. Tüm hakları saklıdır.
      </footer>

      {selected && <CarModal car={selected} onClose={() => setSelected(null)} />}

      <style>{`
        @media (max-width: 900px) {
          .da-filter-grid { grid-template-columns: 1fr 1fr !important; }
          .da-card-grid { grid-template-columns: repeat(2,1fr) !important; }
        }
        @media (max-width: 600px) {
          .da-filter-grid { grid-template-columns: 1fr !important; }
          .da-card-grid { grid-template-columns: 1fr !important; }
        }
      `}</style>
    </div>
  );
}

function CarModal({ car, onClose }) {
  const [sent, setSent] = useState(false);
  return (
    <div onClick={onClose} style={{
      position: "fixed", inset: 0, background: "rgba(30,27,23,0.66)", zIndex: 50,
      display: "flex", alignItems: "center", justifyContent: "center", padding: 20,
    }}>
      <div onClick={(e) => e.stopPropagation()} style={{
        background: "#fff", borderRadius: 16, maxWidth: 760, width: "100%", maxHeight: "88vh",
        overflowY: "auto", fontFamily: "Inter,sans-serif",
      }}>
        <div style={{ position: "relative" }}>
          <img src={car.img} alt={car.title} style={{ width: "100%", height: 320, objectFit: "cover", borderRadius: "16px 16px 0 0" }} />
          <button onClick={onClose} style={{
            position: "absolute", top: 14, right: 14, background: "rgba(39,36,31,0.7)", border: "none",
            borderRadius: 8, width: 34, height: 34, display: "flex", alignItems: "center", justifyContent: "center",
            cursor: "pointer",
          }}>
            <X size={18} color="#fff" />
          </button>
          <div style={{ position: "absolute", top: 14, left: 14 }}><StatusBadge status={car.status} /></div>
        </div>
        <div style={{ padding: 28 }}>
          <h2 style={{ fontFamily: "Oswald,sans-serif", fontSize: 24, color: "#2A2622", margin: "0 0 6px" }}>{car.title}</h2>
          <div style={{ fontFamily: "Oswald,sans-serif", fontSize: 26, color: "#27241F", fontWeight: 600, marginBottom: 18 }}>
            {TL(car.price)}
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12, marginBottom: 24 }}>
            {[
              [Calendar, "Model Yılı", car.year],
              [Gauge, "Kilometre", KM(car.km)],
              [Fuel, "Yakıt", car.fuel],
              [Settings2, "Vites", car.gear],
            ].map(([Icon, label, val], i) => (
              <div key={i} style={{ background: "#F5F6F8", borderRadius: 10, padding: "12px 10px", textAlign: "center" }}>
                <Icon size={16} color="#D1A564" style={{ marginBottom: 6 }} />
                <div style={{ fontSize: 11, color: "#8B93A1", marginBottom: 2 }}>{label}</div>
                <div style={{ fontSize: 13.5, fontWeight: 600, color: "#2A2622" }}>{val}</div>
              </div>
            ))}
          </div>

          <div style={{ display: "flex", alignItems: "center", gap: 8, color: "#8B93A1", fontSize: 13, marginBottom: 20 }}>
            <MapPin size={14} /> Defne Auto Galeri, Isparta — İlan no: {car.id}
          </div>

          {!sent ? (
            <form onSubmit={(e) => { e.preventDefault(); setSent(true); }} style={{ display: "grid", gap: 10 }}>
              <div style={{ fontWeight: 600, fontSize: 14.5, color: "#2A2622", marginBottom: 2 }}>Bu araç için teklif/bilgi al</div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                <input required placeholder="Adınız" style={{ padding: "11px 12px", borderRadius: 9, border: "1px solid #E2E5EA", fontSize: 14 }} />
                <input required placeholder="Telefon" style={{ padding: "11px 12px", borderRadius: 9, border: "1px solid #E2E5EA", fontSize: 14 }} />
              </div>
              <textarea placeholder="Mesajınız (opsiyonel)" rows={3} style={{ padding: "11px 12px", borderRadius: 9, border: "1px solid #E2E5EA", fontSize: 14, fontFamily: "inherit", resize: "vertical" }} />
              <button type="submit" style={{
                background: "#D1A564", color: "#27241F", border: "none", borderRadius: 9, padding: "12px",
                fontWeight: 700, fontSize: 14.5, cursor: "pointer", marginTop: 4,
              }}>
                Talebi Gönder
              </button>
            </form>
          ) : (
            <div style={{ background: "#E6F6EC", color: "#1A7A3E", padding: "16px", borderRadius: 10, fontSize: 14, fontWeight: 500 }}>
              Talebiniz iletildi — Defne Auto ekibi size en kısa sürede dönecek.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

