function AdminSidebar({ tab, setTab, goSite, carCount, leadCount }) {
  const items = [
    { id: "cars", label: "Araçlar", icon: LayoutGrid, badge: carCount },
    { id: "leads", label: "Gelen Talepler", icon: MessageSquare, badge: leadCount },
    { id: "sync", label: "Senkronizasyon", icon: RefreshCw },
  ];
  return (
    <div style={{
      width: 220, background: "#27241F", height: "100%", display: "flex", flexDirection: "column",
      flexShrink: 0,
    }}>
      <div style={{ padding: "20px 16px 16px" }}><Logo size={1.1} light /></div>
      <div style={{ flex: 1, padding: "8px 12px" }}>
        {items.map((it) => {
          const Icon = it.icon;
          const active = tab === it.id;
          return (
            <button key={it.id} onClick={() => setTab(it.id)} style={{
              width: "100%", display: "flex", alignItems: "center", gap: 11, padding: "11px 12px",
              borderRadius: 9, border: "none", marginBottom: 4, cursor: "pointer", textAlign: "left",
              background: active ? "rgba(209,165,100,0.14)" : "transparent",
              color: active ? "#D1A564" : "#D6CBC0", fontSize: 14, fontWeight: 600,
            }}>
              <Icon size={16} />
              <span style={{ flex: 1 }}>{it.label}</span>
              {it.badge != null && it.badge > 0 && (
                <span style={{
                  background: active ? "#D1A564" : "#4A4239", color: active ? "#27241F" : "#E4DCD3",
                  fontSize: 11, fontWeight: 700, borderRadius: 12, padding: "1px 7px",
                }}>{it.badge}</span>
              )}
            </button>
          );
        })}
      </div>
      <div style={{ padding: 14, borderTop: "1px solid #3A332C" }}>
        <button onClick={goSite} style={{
          width: "100%", display: "flex", alignItems: "center", gap: 9, justifyContent: "center",
          background: "transparent", border: "1px solid #544A40", color: "#C9BCB0",
          borderRadius: 8, padding: "10px", fontSize: 13, cursor: "pointer", fontWeight: 500,
        }}>
          <ChevronLeft size={15} /> Siteye Dön
        </button>
      </div>
    </div>
  );
}

function CarFormModal({ initial, onSave, onClose }) {
  const blank = { title: "", brand: "", model: "", year: new Date().getFullYear(), km: 0, fuel: "Benzin", gear: "Manuel", price: 0, img: "" };
  const [form, setForm] = useState(initial || blank);
  const set = (k) => (e) => setForm((f) => ({ ...f, [k]: e.target.value }));
  const inputStyle = { width: "100%", padding: "10px 12px", borderRadius: 9, border: "1px solid #E2E5EA", fontSize: 14, fontFamily: "inherit" };
  const labelStyle = { fontSize: 12, fontWeight: 600, color: "#6B7280", marginBottom: 5, display: "block" };

  return (
    <div onClick={onClose} style={{
      position: "fixed", inset: 0, background: "rgba(30,27,23,0.6)", zIndex: 60,
      display: "flex", alignItems: "center", justifyContent: "center", padding: 20,
    }}>
      <div onClick={(e) => e.stopPropagation()} style={{
        background: "#fff", borderRadius: 14, maxWidth: 520, width: "100%", padding: 26,
        maxHeight: "88vh", overflowY: "auto",
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 18 }}>
          <h3 style={{ margin: 0, fontFamily: "Oswald,sans-serif", fontSize: 19, color: "#2A2622" }}>
            {initial ? "Aracı Düzenle" : "Yeni Araç Ekle"}
          </h3>
          <button onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer" }}><X size={18} color="#8B93A1" /></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); onSave({ ...form, year: Number(form.year), km: Number(form.km), price: Number(form.price) }); }}
          style={{ display: "grid", gap: 12 }}>
          <div><label style={labelStyle}>İlan Başlığı</label><input required style={inputStyle} value={form.title} onChange={set("title")} placeholder="Örn: Renault Clio 1.0 TCe Touch" /></div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
            <div><label style={labelStyle}>Marka</label><input required style={inputStyle} value={form.brand} onChange={set("brand")} /></div>
            <div><label style={labelStyle}>Model</label><input required style={inputStyle} value={form.model} onChange={set("model")} /></div>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
            <div><label style={labelStyle}>Model Yılı</label><input type="number" required style={inputStyle} value={form.year} onChange={set("year")} /></div>
            <div><label style={labelStyle}>Kilometre</label><input type="number" required style={inputStyle} value={form.km} onChange={set("km")} /></div>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
            <div>
              <label style={labelStyle}>Yakıt</label>
              <select style={inputStyle} value={form.fuel} onChange={set("fuel")}>
                <option>Benzin</option><option>Dizel</option><option>Hibrit</option><option>Elektrik</option>
              </select>
            </div>
            <div>
              <label style={labelStyle}>Vites</label>
              <select style={inputStyle} value={form.gear} onChange={set("gear")}>
                <option>Manuel</option><option>Otomatik</option>
              </select>
            </div>
          </div>
          <div><label style={labelStyle}>Fiyat (₺)</label><input type="number" required style={inputStyle} value={form.price} onChange={set("price")} /></div>
          <div><label style={labelStyle}>Görsel URL</label><input style={inputStyle} value={form.img} onChange={set("img")} placeholder="https://..." /></div>
          <button type="submit" style={{
            background: "#27241F", color: "#fff", border: "none", borderRadius: 9, padding: "12px",
            fontWeight: 700, fontSize: 14.5, cursor: "pointer", marginTop: 4,
          }}>
            {initial ? "Değişiklikleri Kaydet" : "Aracı Ekle"}
          </button>
        </form>
      </div>
    </div>
  );
}

function AdminCars({ cars, setCars }) {
  const [editing, setEditing] = useState(null);
  const [showForm, setShowForm] = useState(false);

  const toggleStatus = (id) => setCars((cs) => cs.map((c) => c.id === id
    ? { ...c, status: c.status === "hidden" ? "active" : "hidden" } : c));

  const remove = (id) => { if (window.confirm("Bu aracı silmek istediğine emin misin?")) setCars((cs) => cs.filter((c) => c.id !== id)); };

  const save = (data) => {
    if (editing) {
      setCars((cs) => cs.map((c) => c.id === editing.id ? { ...c, ...data } : c));
    } else {
      const id = "da-" + Math.floor(Math.random() * 9000 + 1000);
      setCars((cs) => [{ id, status: "pending", addedAt: new Date().toISOString().slice(0, 10),
        img: data.img || "https://images.unsplash.com/photo-1502877338535-766e1452684a?q=80&w=1200&auto=format&fit=crop", ...data }, ...cs]);
    }
    setShowForm(false); setEditing(null);
  };

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
        <div>
          <h2 style={{ margin: 0, fontFamily: "Oswald,sans-serif", fontSize: 22, color: "#2A2622" }}>Araçlar</h2>
          <p style={{ margin: "4px 0 0", fontSize: 13.5, color: "#8B93A1" }}>Sahibinden'den otomatik gelen ve manuel eklediğin tüm araçlar.</p>
        </div>
        <button onClick={() => { setEditing(null); setShowForm(true); }} style={{
          display: "flex", alignItems: "center", gap: 7, background: "#D1A564", color: "#27241F",
          border: "none", borderRadius: 9, padding: "11px 16px", fontWeight: 700, fontSize: 14, cursor: "pointer",
        }}>
          <Plus size={16} /> Yeni Araç Ekle
        </button>
      </div>

      <div style={{ background: "#fff", borderRadius: 14, border: "1px solid #EAECEF", overflow: "hidden" }}>
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13.5 }}>
          <thead>
            <tr style={{ background: "#F7F8FA", textAlign: "left" }}>
              {["Araç", "Fiyat", "Eklenme", "Durum", ""].map((h) => (
                <th key={h} style={{ padding: "12px 16px", color: "#8B93A1", fontWeight: 600, fontSize: 12, textTransform: "uppercase", letterSpacing: 0.3 }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {cars.map((c) => (
              <tr key={c.id} style={{ borderTop: "1px solid #F0F1F3" }}>
                <td style={{ padding: "12px 16px" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <img src={c.img} alt="" style={{ width: 52, height: 38, borderRadius: 7, objectFit: "cover" }} />
                    <div>
                      <div style={{ fontWeight: 600, color: "#2A2622" }}>{c.title}</div>
                      <div style={{ color: "#8B93A1", fontSize: 12 }}>{c.year} · {KM(c.km)} · {c.id}</div>
                    </div>
                  </div>
                </td>
                <td style={{ padding: "12px 16px", fontWeight: 600, color: "#2A2622" }}>{TL(c.price)}</td>
                <td style={{ padding: "12px 16px", color: "#8B93A1" }}>{c.addedAt}</td>
                <td style={{ padding: "12px 16px" }}><StatusBadge status={c.status} /></td>
                <td style={{ padding: "12px 16px" }}>
                  <div style={{ display: "flex", gap: 6, justifyContent: "flex-end" }}>
                    <button onClick={() => toggleStatus(c.id)} title={c.status === "hidden" ? "Yayına al" : "Pasife al"} style={iconBtn}>
                      {c.status === "hidden" ? <Eye size={14} /> : <EyeOff size={14} />}
                    </button>
                    <button onClick={() => { setEditing(c); setShowForm(true); }} title="Düzenle" style={iconBtn}><Pencil size={14} /></button>
                    <button onClick={() => remove(c.id)} title="Sil" style={{ ...iconBtn, color: "#C0392B" }}><Trash2 size={14} /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showForm && <CarFormModal initial={editing} onSave={save} onClose={() => { setShowForm(false); setEditing(null); }} />}
    </div>
  );
}

const iconBtn = {
  width: 30, height: 30, borderRadius: 7, border: "1px solid #E2E5EA", background: "#fff",
  display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", color: "#4B5563",
};

function AdminLeads({ leads, cars }) {
  const carTitle = (id) => cars.find((c) => c.id === id)?.title || "Silinmiş ilan";
  return (
    <div>
      <h2 style={{ margin: "0 0 4px", fontFamily: "Oswald,sans-serif", fontSize: 22, color: "#2A2622" }}>Gelen Talepler</h2>
      <p style={{ margin: "0 0 20px", fontSize: 13.5, color: "#8B93A1" }}>Site üzerinden araçlara gelen teklif/bilgi talepleri.</p>
      {leads.length === 0 ? (
        <div style={{ background: "#fff", borderRadius: 14, padding: 40, textAlign: "center", color: "#8B93A1", border: "1px dashed #E2E5EA" }}>
          Henüz gelen talep yok.
        </div>
      ) : (
        <div style={{ display: "grid", gap: 10 }}>
          {leads.map((l) => (
            <div key={l.id} style={{ background: "#fff", border: "1px solid #EAECEF", borderRadius: 12, padding: 16, display: "flex", gap: 14, alignItems: "flex-start" }}>
              <div style={{
                width: 38, height: 38, borderRadius: 9, background: "#FFF3DD", color: "#A86A00",
                display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0,
              }}><MessageSquare size={16} /></div>
              <div style={{ flex: 1 }}>
                <div style={{ display: "flex", justifyContent: "space-between" }}>
                  <span style={{ fontWeight: 600, color: "#2A2622", fontSize: 14.5 }}>{l.name}</span>
                  <span style={{ fontSize: 12, color: "#8B93A1" }}>{l.at}</span>
                </div>
                <div style={{ fontSize: 13, color: "#8B93A1", margin: "2px 0 6px" }}>{l.phone} · İlgilendiği araç: {carTitle(l.carId)}</div>
                {l.note && <div style={{ fontSize: 13.5, color: "#374151", background: "#F7F8FA", padding: "8px 11px", borderRadius: 8 }}>{l.note}</div>}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function AdminSync() {
  const [lastSync, setLastSync] = useState("2026-06-22 23:00");
  const [syncing, setSyncing] = useState(false);

  const runSync = () => {
    setSyncing(true);
    setTimeout(() => {
      setSyncing(false);
      setLastSync(new Date().toLocaleString("tr-TR").slice(0, 17));
    }, 1400);
  };

  return (
    <div>
      <h2 style={{ margin: "0 0 4px", fontFamily: "Oswald,sans-serif", fontSize: 22, color: "#2A2622" }}>Sahibinden Senkronizasyonu</h2>
      <p style={{ margin: "0 0 20px", fontSize: 13.5, color: "#8B93A1" }}>
        Bu ekran, sahibinden Oto Galerim API bağlantısının canlı durumunu gösterir.
      </p>

      <div style={{ background: "#fff", borderRadius: 14, border: "1px solid #EAECEF", padding: 24, marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
              <span style={{ width: 9, height: 9, borderRadius: "50%", background: "#22A45D", display: "inline-block" }} />
              <span style={{ fontWeight: 600, color: "#2A2622", fontSize: 15 }}>Bağlantı Aktif</span>
            </div>
            <div style={{ fontSize: 13, color: "#8B93A1" }}>Son senkronizasyon: {lastSync}</div>
          </div>
          <button onClick={runSync} disabled={syncing} style={{
            display: "flex", alignItems: "center", gap: 7, background: syncing ? "#EAECEF" : "#27241F",
            color: syncing ? "#8B93A1" : "#fff", border: "none", borderRadius: 9, padding: "11px 16px",
            fontWeight: 600, fontSize: 13.5, cursor: syncing ? "default" : "pointer",
          }}>
            <RefreshCw size={15} style={{ animation: syncing ? "spin 1s linear infinite" : "none" }} />
            {syncing ? "Senkronize ediliyor..." : "Şimdi Senkronize Et"}
          </button>
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12 }}>
        {[
          ["Senkron sıklığı", "Her 30 dakika"],
          ["Galeri kaynağı", "defneauto32.sahibinden.com"],
          ["Otomatik kaldırma", "Açık"],
        ].map(([label, val]) => (
          <div key={label} style={{ background: "#fff", border: "1px solid #EAECEF", borderRadius: 12, padding: 16 }}>
            <div style={{ fontSize: 11.5, color: "#8B93A1", marginBottom: 4, textTransform: "uppercase", letterSpacing: 0.3 }}>{label}</div>
            <div style={{ fontSize: 14.5, fontWeight: 600, color: "#2A2622" }}>{val}</div>
          </div>
        ))}
      </div>

      <div style={{ marginTop: 18, fontSize: 12.5, color: "#8B93A1", background: "#F7F8FA", padding: 14, borderRadius: 10, lineHeight: 1.6 }}>
        Not: Bu panel, gerçek sahibinden API bağlantısının nasıl görüneceğini gösteren bir arayüz taslağıdır.
        Canlıda bu ekranı gerçek API verisine bağlamak için geliştiricinin kurduğu senkronizasyon servisine bağlanması gerekir.
      </div>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

function AdminPanel({ cars, setCars, leads, goSite }) {
  const [tab, setTab] = useState("cars");
  return (
    <div style={{ display: "flex", height: "100%", background: "#F5F6F8", fontFamily: "Inter,sans-serif" }}>
      <AdminSidebar tab={tab} setTab={setTab} goSite={goSite} carCount={cars.length} leadCount={leads.length} />
      <div style={{ flex: 1, padding: "28px 32px", overflowY: "auto" }}>
        {tab === "cars" && <AdminCars cars={cars} setCars={setCars} />}
        {tab === "leads" && <AdminLeads leads={leads} cars={cars} />}
        {tab === "sync" && <AdminSync />}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
export default function DefneAutoApp() {
  const [view, setView] = useState("site");
  const [cars, setCars] = useState(seedCars);
  const [leads] = useState(seedLeads);

  return (
    <div style={{ height: "100vh", width: "100%" }}>
      {view === "site"
        ? <PublicSite cars={cars} goAdmin={() => setView("admin")} />
        : <AdminPanel cars={cars} setCars={setCars} leads={leads} goSite={() => setView("site")} />}
    </div>
  );
}
